#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10,M=2e6+10,INF=0x3f3f3f3f;
struct Graph
{
	int head[N],des[M],cap[M],nxt[M],cnt;
	inline void ins(int x,int y,int z){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;cap[cnt]=z;}
	inline void Init(){memset(head,0,sizeof(head));cnt=1;}
}a;
int s,t,que[N],H,T,n,m;
int dep[N];
inline bool bfs()
{
	memset(dep,0,sizeof(dep));dep[que[H=T=1]=s]=1;
	while(H<=T){int u=que[H++];grep(a,u,i){int v=a.des[i];if(a.cap[i]&&!dep[v])dep[que[++T]=v]=dep[u]+1;}}return dep[t];
}
int dfs(int u,int in)
{
	if(u==t)return in;int out=0;grep(a,u,i)
	{
		int v=a.des[i];if(a.cap[i]&&dep[v]==dep[u]+1)
		{
			int tmp=dfs(v,min(in,a.cap[i]));
			a.cap[i]-=tmp;in-=tmp;a.cap[i^1]+=tmp;out+=tmp;
		}	if(!in)break;
	}
	if(!out)dep[u]=0;return out;
}
inline int dinic(int u,int v){s=u;t=v;int res=0;while(bfs())res+=dfs(s,INF);return res;}
inline int Cnt(int x,int y){return (x-1)*m+y;} inline bool jud(int x,int y){return x>0&&y>0&&x<=n&&y<=m;}
int main()
{
	n=read();m=read();a.Init();int sum=0;rep(1,n,i)
	{
		int tmp=i&1;rep(1,m,j)
		{
			tmp^=1;int z=read();sum+=z; 
			if(!tmp)
			{
				a.ins(n*m+1,Cnt(i,j),z),a.ins(Cnt(i,j),n*m+1,0);
				if(jud(i+1,j))a.ins(Cnt(i,j),Cnt(i+1,j),INF),a.ins(Cnt(i+1,j),Cnt(i,j),0);
				if(jud(i,j+1))a.ins(Cnt(i,j),Cnt(i,j+1),INF),a.ins(Cnt(i,j+1),Cnt(i,j),0);
			}			
			else 
			{
				a.ins(Cnt(i,j),n*m+2,z),a.ins(n*m+2,Cnt(i,j),0);
				if(jud(i+1,j))a.ins(Cnt(i,j),Cnt(i+1,j),0),a.ins(Cnt(i+1,j),Cnt(i,j),INF);
				if(jud(i,j+1))a.ins(Cnt(i,j),Cnt(i,j+1),0),a.ins(Cnt(i,j+1),Cnt(i,j),INF);
			} 
		}
	}
//	rep(1,n*m+2,i)grep(a,i,j)printf("%d %d %d\n",i,a.des[j],a.cap[j]>10000?-1:a.cap[j]);
	printf("%d\n",sum-dinic(n*m+1,n*m+2));
}
